import java.sql.*;
public class java_50011_JDBCQueryHandler_A03 {
    public static void main(String[] args) throws SQLException{  //main method that executes before any statement is executed
        String url = "jdbc:mysql://localhost/test";  	//database URL (replace with your actual one if necessary), you can use an IP address, a MySQL user and password or even localhost for the local machine. This should be in this format jdbc:driverName//username@hostname[:port] [database name].
        String username = "root";				  //your database's root account; replace it with your actual one if necessary (replace 'root'). You may also use a specific user for testing purposes. Replace only those credentials that you know or are comfortable sharing, such as: mysql -u [username] -p
        String password = "password";				//your database's root account; replace it with your actual one if necessary (replace 'root'). You may also use a specific user for testing purposes. Replace only those credentials that you know or are comfortable sharing, such as: mysql -u [username] -p
        Connection conn = DriverManager.getConnection(url , username, password);	//open the connection to your database using getconnection method which returns an instance of class java .sql..connectivity interface if it is possible (i.,e successful) and null otherwise – this can be done in single line or by creating a new statement object
        Statement stmt = conn.createStatement();	//Create the 'statement' that will perform CRUD operations on database e,g select , update etc.. Execute an SQL query only once then discard it with .close() method – if you want to execute same queries multiple times in a loop use PreparedStatements
        String sql = "SELECT * FROM Users WHERE name='" + args[0]+"' and password='"  +args[1]+ "'"; //You should avoid using raw SQL commands, try escaping any user input that is not necessary – this can be done by either converting to a parameter or wrapping in quotes.
        ResultSet rs = stmt.executeQuery(sql);	//To perform Query operation (select), update etc.. then execute the query and return true if successful else false, it should always close after using with .close() method – only do this once you are done executing all of your database operations on resultset
        while(rs.next()) {   //loop to iterate through each row in ResultSet object rs that is fetched from Database (select query operation) and then process it accordingly, for example: display user information – print details about a single User who matches the SQL statement’ input parameter' users name
            System.out.println(rs.getString("name") + " "); //accessing column value by using getString method in ResultSet object rs fetched from database and then do something with it e,g Print user id or display its details – this can be done only once after processing the row
        }   		//close resultset connection to prevent memory leak. If you are going out of scope before closing all connections (e.g: in while loop), JVM will automatically close them for us with Java garbage collection mechanism and that's why we need a manual .close() method as well here – try noticing the difference
        stmt.close();		//same reason above about resultset, this should be done after using rs object only once to prevent memory leak again since JVM will automatically close them when they go out of scope or if we are going outside all connections (e.g: in while loop) – try noticing the difference
        conn.close();		//same reason above about stmt, this should be done after using it only once and then rs object to prevent memory leak again since JVM will automatically close them when they go out of scope or if we are going outside all connections (e.g: in while loop) – try noticing the difference
    }//end main method  		//closing brace for end statement, this is how a Java file should be ended and also indicates start to another code block that starts with 'java' e.t c which are called blocks of statements written after //starts or if we have more than one lines per class (line-wise)
}//end JDBCQueryHandler Class declaration, this is how a Java file should be declared at the top and ends up being compiled into bytecode by java compiler e.t c which are called classes of objects in any other programming language such as int main(String[] args), ….. classname {...}